SESSION_PREFIX = "session:"
SESSION_EXPIRY = 3600  # 1 hour in seconds


class RedisSessionManager:
    """Manages user sessions using Redis SET/GET commands."""

    def __init__(self, redis_conn, prefix=SESSION_PREFIX, expiry=SESSION_EXPIRY):
        self.redis = redis_conn
        self.prefix = prefix
        self.expiry = expiry

    def create_session(self, user_data):
        """Create a new session and return the session ID."""
        session_id = str(uuid.uuid4())
        key = f"{self.prefix}{session_id}"
        session_data = {
            "user_data": user_data,
            "created_at": datetime.utcnow().isoformat(),
            "last_accessed": datetime.utcnow().isoformat()
        }
        # Use SET with expiry for automatic cleanup
        self.redis.set(key, json.dumps(session_data), ex=self.expiry)
        return session_id

    def get_session(self, session_id):
        """Retrieve session data by session ID using GET."""
        key = f"{self.prefix}{session_id}"
        data = self.redis.get(key)
        if data is None:
            return None
        session_data = json.loads(data)
        # Update last accessed time and refresh TTL
        session_data["last_accessed"] = datetime.utcnow().isoformat()
        self.redis.set(key, json.dumps(session_data), ex=self.expiry)
        return session_data

    def update_session(self, session_id, updates):
        """Update session data."""
        session_data = self.get_session(session_id)
        if session_data is None:
            return False
        session_data["user_data"].update(updates)
        session_data["last_accessed"] = datetime.utcnow().isoformat()
        key = f"{self.prefix}{session_id}"
        self.redis.set(key, json.dumps(session_data), ex=self.expiry)
        return True

    def destroy_session(self, session_id):
        """Delete a session."""
        key = f"{self.prefix}{session_id}"
        return self.redis.delete(key) > 0

    def get_active_session_count(self):
        """Get count of active sessions."""
        pattern = f"{self.prefix}*"
        count = 0
        for _ in self.redis.scan_iter(match=pattern, count=100):
            count += 1
        return count


session_manager = RedisSessionManager(redis_client)


