CACHE_PREFIX = "cache:"
DEFAULT_CACHE_TTL = 300  # 5 minutes


def redis_cache(ttl=DEFAULT_CACHE_TTL, prefix=CACHE_PREFIX, key_builder=None):
    """
    Caching decorator for expensive database queries and computations.

    Args:
        ttl: Time-to-live in seconds for cached results.
        prefix: Cache key prefix.
        key_builder: Optional custom function to build cache keys.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key
            if key_builder:
                cache_key = f"{prefix}{key_builder(*args, **kwargs)}"
            else:
                # Generate key from function name and arguments
                key_parts = [func.__module__, func.__qualname__]
                if args:
                    # Skip 'self' for methods
                    key_parts.append(str(args))
                if kwargs:
                    key_parts.append(str(sorted(kwargs.items())))
                raw_key = ":".join(key_parts)
                hashed = hashlib.md5(raw_key.encode()).hexdigest()
                cache_key = f"{prefix}{func.__qualname__}:{hashed}"

            # Try to get from cache
            try:
                cached = cache_client.get(cache_key)
                if cached is not None:
                    result = json.loads(cached)
                    # Add cache metadata
                    if isinstance(result, dict):
                        result['_cache_hit'] = True
                    return result
            except (redis.RedisError, json.JSONDecodeError) as e:
                app.logger.warning(f"Cache read error: {e}")

            # Execute function if cache miss
            result = func(*args, **kwargs)

            # Store in cache
            try:
                cache_data = result
                if isinstance(cache_data, dict):
                    cache_data = {**cache_data, '_cached_at': datetime.utcnow().isoformat()}
                cache_client.set(cache_key, json.dumps(cache_data), ex=ttl)
            except (redis.RedisError, TypeError) as e:
                app.logger.warning(f"Cache write error: {e}")

            return result

        # Add cache invalidation method
        def invalidate(*args, **kwargs):
            if key_builder:
                cache_key = f"{prefix}{key_builder(*args, **kwargs)}"
            else:
                key_parts = [func.__module__, func.__qualname__]
                if args:
                    key_parts.append(str(args))
                if kwargs:
                    key_parts.append(str(sorted(kwargs.items())))
                raw_key = ":".join(key_parts)
                hashed = hashlib.md5(raw_key.encode()).hexdigest()
                cache_key = f"{prefix}{func.__qualname__}:{hashed}"
            cache_client.delete(cache_key)

        def invalidate_all():
            """Invalidate all cache entries for this function."""
            pattern = f"{prefix}{func.__qualname__}:*"
            keys = list(cache_client.scan_iter(match=pattern, count=100))
            if keys:
                cache_client.delete(*keys)

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all
        return wrapper
    return decorator


