@app.route('/api/cache/invalidate', methods=['POST'])
@require_session
def invalidate_cache():
    """Invalidate specific cache entries."""
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body required"}), 400

    target = data.get('target')
    invalidated = []

    if target == 'user_profile':
        user_id = data.get('user_id')
        if user_id:
            get_user_profile.invalidate(user_id)
            invalidated.append(f"user_profile:{user_id}")
        else:
            get_user_profile.invalidate_all()
            invalidated.append("all user_profiles")

    elif target == 'products':
        get_product_list.invalidate_all()
        invalidated.append("all product_lists")

    elif target == 'dashboard':
        get_dashboard_stats.invalidate_all()
        invalidated.append("dashboard_stats")

    elif target == 'all':
        get_user_profile.invalidate_all()
        get_product_list.invalidate_all()
        get_dashboard_stats.invalidate_all()
        invalidated.append("all caches")

    else:
        return jsonify({"error": f"Unknown cache target: {target}"}), 400

    return jsonify({
        "message": "Cache invalidated",
        "invalidated": invalidated
    })


@app.route('/api/health', methods=['GET'])
def health_check():
    """Detailed health check including Redis connectivity."""
    health = {
        "app": "healthy",
        "timestamp": datetime.utcnow().isoformat()
    }

    # Check session Redis
    try:
        start = time.time()
        redis_client.ping()
        session_redis_latency = round((time.time() - start) * 1000, 2)
        health["session_redis"] = {
            "status": "connected",
            "latency_ms": session_redis_latency,
            "info": {
                "connected_clients": redis_client.info()["connected_clients"],
                "used_memory_human": redis_client.info()["used_memory_human"],
                "db_keys": redis_client.dbsize()
            }
        }
    except redis.RedisError as e:
        health["session_redis"] = {"status": "error", "error": str(e)}

    # Check cache Redis
    try:
        start = time.time()
        cache_client.ping()
        cache_redis_latency = round((time.time() - start) * 1000, 2)
        health["cache_redis"] = {
            "status": "connected",
            "latency_ms": cache_redis_latency,
            "db_keys": cache_client.dbsize()
        }
    except redis.RedisError as e:
        health["cache_redis"] = {"status": "error", "error": str(e)}

    # Active sessions count
    try:
        health["active_sessions"] = session_manager.get_active_session_count()
    except redis.RedisError:
        health["active_sessions"] = "unknown"

    overall_healthy = all(
        health.get(k, {}).get("status") == "connected"
        for k in ["session_redis", "cache_redis"]
    )
    health["overall"] = "healthy" if overall_healthy else "degraded"

    status_code = 200 if overall_healthy else 503
    return jsonify(health), status_code


@app.route('/api/benchmark', methods=['GET'])
def benchmark():
    """
    Benchmark endpoint to demonstrate cache performance.
    Calls cached function twice - first miss, then hit.
    """
    # Invalidate first
    test_user_id = "benchmark_user"
    get_user_profile.invalidate(test_user_id)

    # First call - cache miss
    start = time.time()
    result1 = get_user_profile(test_user_id)
    miss_time = round((time.time() - start) * 1000, 2)

    # Second call - cache hit
    start = time.time()
    result2 = get_user_profile(test_user_id)
    hit_time = round((time.time() - start) * 1000, 2)

    # Cleanup
    get_user_profile.invalidate(test_user_id)

    speedup = round(miss_time / hit_time, 1) if hit_time > 0 else float('inf')

    return jsonify({
        "benchmark_results": {
            "cache_miss_ms": miss_time,
            "cache_hit_ms": hit_time,
            "speedup_factor": f"{speedup}x",
            "first_call_cached": result1.get('_cache_hit', False),
            "second_call_cached": result2.get('_cache_hit', False)
        }
    })


